exercises.solution:
function pipe(value: string, fns: ((s: string) => string)[]): string {
  let result = value;
  for (const fn of fns) {
    result = fn(result);
  }
  return result;
}

const result = pipe("hello world", [
  s => s.toUpperCase(),
  s => s.replace(" ", "-"),
  s => `[${s}]`
]);
console.log(result);

