console.log(calculate("product", 2, 3, 4));
console.log(calculate("average", 10, 20, 30));

exercises.solution:
function calculate(operation: "sum" | "product" | "average", ...numbers: number[]): number {
  switch (operation) {
    case "sum":
      return numbers.reduce((a, b) => a + b, 0);
    case "product":
      return numbers.reduce((a, b) => a * b, 1);
    case "average":
      return numbers.reduce((a, b) => a + b, 0) / numbers.length;
  }
}

console.log(calculate("sum", 1, 2, 3, 4));
console.log(calculate("product", 2, 3, 4));
console.log(calculate("average", 10, 20, 30));

