// Write the generic groupBy function


const people = [
  { name: "Alice", dept: "Engineering" },
  { name: "Bob", dept: "Design" },
  { name: "Charlie", dept: "Engineering" },
  { name: "Diana", dept: "Design" }
];

const byDept = groupBy(people, p => p.dept);
console.log(Object.keys(byDept).sort().join(", "));
console.log(byDept["Engineering"].map(p => p.name).join(", "));
console.log(byDept["Design"].map(p => p.name).join(", "));

exercises.solution:
function groupBy<T>(items: T[], keyFn: (item: T) => string): Record<string, T[]> {
  const result: Record<string, T[]> = {};
  for (const item of items) {
    const key = keyFn(item);
    if (!result[key]) {
      result[key] = [];
    }
    result[key].push(item);
  }
  return result;
}

const people = [
  { name: "Alice", dept: "Engineering" },
  { name: "Bob", dept: "Design" },
  { name: "Charlie", dept: "Engineering" },
  { name: "Diana", dept: "Design" }
];

const byDept = groupBy(people, p => p.dept);
console.log(Object.keys(byDept).sort().join(", "));
console.log(byDept["Engineering"].map(p => p.name).join(", "));
console.log(byDept["Design"].map(p => p.name).join(", "));

